+        (n, ops) in arb_union_find(15),
+        x_frac in 0.0f64..1.0,
+    ) {
+        let x = frac_to_idx(x_frac, n);
+        let mut uf = build_uf(n, &ops);
+        let root = uf.find(x);
+        let members = uf.component_members(x);
+        for &m in &members {
+            prop_assert_eq!(uf.find(m), root, "member {} has different root", m);
+        }
+    }
